175→size_t DdsSubscriptionManager::ref_count(const std::string& topic_name) const {
176→  std::lock_guard<std::mutex> lock(mutex_);
177→
178→  auto it = subscriptions_.find(topic_name);
179→  if (it != subscriptions_.end()) {
180→    return it->second.reference_count;
181→  }
182→
183→  return 0;
184→}
