 24→namespace pj_bridge {
 25→
 26→class DdsSubscriptionManager::InternalReaderListener
 27→    : public dds::sub::NoOpDataReaderListener<dds::core::xtypes::DynamicData> {
 28→ public:
 29→  InternalReaderListener(const std::string& topic_name, DdsSubscriptionManager& manager)
 30→      : topic_name_(topic_name), manager_(manager) {}
 31→
 32→  void on_data_available(dds::sub::DataReader<dds::core::xtypes::DynamicData>& reader) override {
 33→    try {
 34→      auto samples = reader.take();
 35→
 36→      DdsMessageCallback cb;
 37→      {
 38→        std::lock_guard<std::mutex> lock(manager_.mutex_);
 39→        cb = manager_.callback_;
 40→      }
 41→
 42→      if (!cb) {
 43→        return;
 44→      }
 45→
 46→      for (const auto& sample : samples) {
 47→        if (!sample.info().valid()) {
 48→          continue;
 49→        }
 50→
 51→        auto cdr_buffer = sample.data().get_cdr_buffer();
 52→        const auto* raw_data = reinterpret_cast<const std::byte*>(cdr_buffer.first);
 53→        uint32_t data_size = cdr_buffer.second;
 54→
 55→        auto cdr_data = std::make_shared<std::vector<std::byte>>(raw_data, raw_data + data_size);
 56→
 57→        const auto& source_ts = sample.info().source_timestamp();
 58→        uint64_t timestamp_ns = (static_cast<uint64_t>(source_ts.sec()) * 1'000'000'000ULL) + source_ts.nanosec();
 59→
 60→        cb(topic_name_, std::move(cdr_data), timestamp_ns);
 61→      }
 62→    } catch (const std::exception& e) {
 63→      spdlog::error("Exception in DataReaderListener for '{}': {}", topic_name_, e.what());
 64→    }
 65→  }
 66→
 67→ private:
 68→  std::string topic_name_;
 69→  DdsSubscriptionManager& manager_;
 70→};
 71→
 72→DdsSubscriptionManager::DdsSubscriptionManager(DdsTopicDiscovery& discovery) : discovery_(discovery) {}
 73→
 74→DdsSubscriptionManager::~DdsSubscriptionManager() {
 75→  unsubscribe_all();
 76→}
 77→
 78→void DdsSubscriptionManager::set_message_callback(DdsMessageCallback callback) {
 79→  std::lock_guard<std::mutex> lock(mutex_);
 80→  callback_ = std::move(callback);
 81→}
 82→
 83→bool DdsSubscriptionManager::subscribe(const std::string& topic_name) {
 84→  std::lock_guard<std::mutex> lock(mutex_);
 85→
 86→  auto it = subscriptions_.find(topic_name);
 87→  if (it != subscriptions_.end()) {
 88→    it->second.reference_count++;
 89→    spdlog::debug("Incremented ref count for '{}' to {}", topic_name, it->second.reference_count);
 90→    return true;
 91→  }
 92→
 93→  auto struct_type_opt = discovery_.get_type(topic_name);
 94→  if (!struct_type_opt) {
 95→    spdlog::error("Topic '{}' not found in discovery", topic_name);
 96→    return false;
 97→  }
 98→
 99→  auto domain_id_opt = discovery_.get_domain_id(topic_name);
100→  if (!domain_id_opt) {
101→    spdlog::error("No domain ID for topic '{}'", topic_name);
102→    return false;
103→  }
104→
105→  auto& struct_type = *struct_type_opt;
106→
107→  try {
108→    auto participant = discovery_.get_participant(*domain_id_opt);
109→
110→    rti::core::xtypes::DynamicDataTypeSerializationProperty ser_prop;
111→    ser_prop.skip_deserialization(true);
112→
113→    rti::domain::register_type(participant, struct_type.name(), struct_type, ser_prop);
114→
115→    dds::topic::Topic<dds::core::xtypes::DynamicData> topic(participant, topic_name, struct_type.name());
116→
117→    dds::sub::Subscriber subscriber(participant);
118→    dds::sub::DataReader<dds::core::xtypes::DynamicData> reader(subscriber, topic);
119→
120→    auto listener = std::make_shared<InternalReaderListener>(topic_name, *this);
121→    reader.set_listener(listener);
122→
123→    subscriptions_.emplace(
124→        std::piecewise_construct, std::forward_as_tuple(topic_name),
125→        std::forward_as_tuple(subscriber, reader, listener, 1));
126→
127→    spdlog::info("Subscribed to '{}' (type: '{}', domain: {})", topic_name, struct_type.name(), *domain_id_opt);
128→    return true;
129→  } catch (const std::exception& e) {
130→    spdlog::error("Failed to subscribe to '{}': {}", topic_name, e.what());
131→    return false;
132→  }
133→}
134→
135→bool DdsSubscriptionManager::unsubscribe(const std::string& topic_name) {
136→  std::optional<SubscriptionInfo> to_close;
137→
138→  {
139→    std::lock_guard<std::mutex> lock(mutex_);
140→
141→    auto it = subscriptions_.find(topic_name);
142→    if (it == subscriptions_.end()) {
143→      return false;
144→    }
145→
146→    if (it->second.reference_count == 0) {
147→      return false;
148→    }
149→
150→    it->second.reference_count--;
151→    spdlog::debug("Decremented ref count for '{}' to {}", topic_name, it->second.reference_count);
152→
153→    if (it->second.reference_count == 0) {
154→      to_close.emplace(std::move(it->second));
155→      subscriptions_.erase(it);
156→    }
157→  }
158→
159→  if (to_close) {
160→    try {
161→      to_close->reader.set_listener(nullptr);
162→      to_close->reader.close();
163→      to_close->subscriber.close();
164→    } catch (const std::exception& e) {
165→      spdlog::warn("Error cleaning up reader for '{}': {}", topic_name, e.what());
166→    } catch (...) {
167→      spdlog::warn("Unknown error cleaning up reader for '{}'", topic_name);
168→    }
169→    spdlog::info("Unsubscribed from '{}' (reader destroyed)", topic_name);
170→  }
171→
172→  return true;
173→}
174→
175→size_t DdsSubscriptionManager::ref_count(const std::string& topic_name) const {
176→  std::lock_guard<std::mutex> lock(mutex_);
177→
178→  auto it = subscriptions_.find(topic_name);
179→  if (it != subscriptions_.end()) {
180→    return it->second.reference_count;
181→  }
182→
183→  return 0;
184→}
185→
186→void DdsSubscriptionManager::unsubscribe_all() {
187→  std::unordered_map<std::string, SubscriptionInfo> to_close;
188→
189→  {
190→    std::lock_guard<std::mutex> lock(mutex_);
191→    to_close.swap(subscriptions_);
192→  }
193→
194→  spdlog::debug("[shutdown] unsubscribe_all: {} subscriptions to close", to_close.size());
195→  for (auto& [name, info] : to_close) {
196→    try {
197→      spdlog::debug("[shutdown] Closing reader for '{}'...", name);
198→      info.reader.set_listener(nullptr);
199→      info.reader.close();
200→      info.subscriber.close();
201→      spdlog::debug("[shutdown] Closed '{}'", name);
202→    } catch (const std::exception& e) {
203→      spdlog::warn("Error cleaning up reader for '{}': {}", name, e.what());
204→    } catch (...) {
205→      spdlog::warn("Unknown error cleaning up reader for '{}'", name);
206→    }
207→  }
208→  spdlog::debug("[shutdown] unsubscribe_all complete");
209→}
210→
211→}  // namespace pj_bridge
