### 5. DynamicData Subscription

**Headers:**
```cpp
#include <fastdds/dds/xtypes/dynamic_types/DynamicPubSubType.hpp>
#include <fastdds/dds/xtypes/dynamic_types/DynamicData.hpp>
#include <fastdds/dds/xtypes/dynamic_types/DynamicDataFactory.hpp>
#include <fastdds/dds/xtypes/dynamic_types/DynamicType.hpp>
#include <fastdds/dds/topic/TypeSupport.hpp>
#include <fastdds/dds/subscriber/Subscriber.hpp>
#include <fastdds/dds/subscriber/DataReader.hpp>
#include <fastdds/dds/subscriber/DataReaderListener.hpp>
#include <fastdds/dds/subscriber/SampleInfo.hpp>
```

**Creating DynamicPubSubType from DynamicType:**

`DynamicPubSubType` constructors:
```cpp
DynamicPubSubType();  // default
DynamicPubSubType(traits<DynamicType>::ref_type type);
DynamicPubSubType(traits<DynamicType>::ref_type type,
                  const xtypes::TypeInformation& type_information);
```

Note: `traits<DynamicType>::ref_type` is the same as `DynamicType::_ref_type`.

**Registering with participant:**
```cpp
DynamicType::_ref_type remote_type =
    DynamicTypeBuilderFactory::get_instance()->create_type_w_type_object(
        remote_type_object)->build();

TypeSupport dyn_type_support(new DynamicPubSubType(remote_type));
dyn_type_support.register_type(participant);
// Registers under the type's built-in name
// Or with explicit name: dyn_type_support.register_type(participant, "MyTypeName");
```

**Creating Topic and DataReader:**
```cpp
Topic* topic = participant->create_topic(
    "my_topic",
    dyn_type_support.get_type_name(),
    TOPIC_QOS_DEFAULT);

Subscriber* subscriber = participant->create_subscriber(SUBSCRIBER_QOS_DEFAULT);

DataReader* data_reader = subscriber->create_datareader(
    topic,
    DATAREADER_QOS_DEFAULT,
    &my_reader_listener);   // DataReaderListener*
```

**DataReaderListener on_data_available callback:**
```cpp
class MyReaderListener : public DataReaderListener
{
    DynamicType::_ref_type dyn_type_;

public:
    void on_data_available(DataReader* reader) override
    {
        DynamicData::_ref_type new_data =
            DynamicDataFactory::get_instance()->create_data(dyn_type_);
        SampleInfo info;

        while (RETCODE_OK == reader->take_next_sample(&new_data, &info))
        {
            if (info.valid_data && info.instance_state == ALIVE_INSTANCE_STATE)
            {
                // Process new_data
            }
        }
    }
};
```

**Complete workflow from the eProsima docs code tester (from `on_data_writer_discovery`):**
```cpp
// 1. Get TypeObject from registry
xtypes::TypeObject remote_type_object;
if (RETCODE_OK != DomainParticipantFactory::get_instance()
        ->type_object_registry().get_type_object(
            info.type_information.type_information.complete()
                .typeid_with_size().type_id(),
            remote_type_object))
{
    return;
}

// 2. Build DynamicType
DynamicType::_ref_type remote_type =
    DynamicTypeBuilderFactory::get_instance()->create_type_w_type_object(
        remote_type_object)->build();

// 3. Register
TypeSupport dyn_type_support(new DynamicPubSubType(remote_type));
dyn_type_support.register_type(participant);

// 4. Create subscriber + datareader
Subscriber* subscriber = participant->create_subscriber(SUBSCRIBER_QOS_DEFAULT);
Topic* topic = participant->create_topic(
    std::string(info.topic_name),
    dyn_type_support.get_type_name(),
    TOPIC_QOS_DEFAULT);
DataReader* data_reader = subscriber->create_datareader(
    topic, DATAREADER_QOS_DEFAULT, &listener);
```

Sources: [TypeSupport docs (3.4)](https://fast-dds.docs.eprosima.com/en/latest/fastdds/dds_layer/topic/typeSupport/typeSupport.html), [Dynamic Language Binding (3.1)](https://fast-dds.docs.eprosima.com/en/3.1.x/fastdds/xtypes/language_binding.html), [Fast-DDS-docs DDSCodeTester.cpp](https://github.com/eProsima/Fast-DDS-docs/blob/master/code/DDSCodeTester.cpp)

