 35→using namespace eprosima::fastdds::dds;
 36→using eprosima::fastdds::rtps::WriterDiscoveryStatus;
 37→
 38→namespace pj_bridge {
 39→
 40→// ---------------------------------------------------------------------------
 41→// ParticipantListener — handles on_data_writer_discovery callbacks
 42→// ---------------------------------------------------------------------------
 43→class FastDdsTopicSource::ParticipantListener : public DomainParticipantListener {
 44→ public:
 45→  ParticipantListener(FastDdsTopicSource& source, int32_t domain_id) : source_(source), domain_id_(domain_id) {}
 46→
 47→  void on_data_writer_discovery(
 48→      DomainParticipant* /*participant*/, WriterDiscoveryStatus reason,
 49→      const PublicationBuiltinTopicData& info, bool& should_be_ignored) override {
 50→    should_be_ignored = false;
 51→
 52→    if (reason != WriterDiscoveryStatus::DISCOVERED_WRITER) {
 53→      return;
 54→    }
 55→
 56→    try {
 57→      std::string topic_name(info.topic_name);
 58→      std::string type_name(info.type_name);
 59→
 60→      // Skip if already cached (fast check before heavy TypeObject work)
 61→      {
 62→        std::shared_lock<std::shared_mutex> lock(source_.mutex_);
 63→        if (source_.topics_.count(topic_name) > 0) {
 64→          return;
 65→        }
 66→      }
 67→
 68→      // Get TypeObject from the global registry via the type identifier in the
 69→      // discovery info's TypeInformation
 70→      xtypes::TypeObject type_object;
 71→      auto& registry = DomainParticipantFactory::get_instance()->type_object_registry();
 72→      const auto& type_id =
 73→          info.type_information.type_information.complete().typeid_with_size().type_id();
 74→
 75→      if (RETCODE_OK != registry.get_type_object(type_id, type_object)) {
 76→        spdlog::debug(
 77→            "Topic '{}' discovered but TypeObject not yet in registry (domain {})", topic_name, domain_id_);
 78→        return;
 79→      }
 80→
 81→      // Build DynamicType
 82→      auto builder = DynamicTypeBuilderFactory::get_instance()->create_type_w_type_object(type_object);
 83→      if (!builder) {
 84→        spdlog::warn("Failed to create DynamicTypeBuilder for '{}' (domain {})", topic_name, domain_id_);
 85→        return;
 86→      }
 87→      DynamicType::_ref_type dynamic_type = builder->build();
 88→      if (!dynamic_type) {
 89→        spdlog::warn("Failed to build DynamicType for '{}' (domain {})", topic_name, domain_id_);
 90→        return;
 91→      }
 92→
 93→      // Only accept struct types (like RTI backend)
 94→      if (dynamic_type->get_kind() != TK_STRUCTURE) {
 95→        spdlog::debug("Topic '{}' has non-struct type '{}', skipping", topic_name, type_name);
 96→        return;
 97→      }
 98→
 99→      // Generate OMG IDL schema
100→      std::ostringstream oss;
101→      if (RETCODE_OK != idl_serialize(dynamic_type, oss)) {
102→        spdlog::warn("Failed to serialize IDL for '{}' (domain {})", topic_name, domain_id_);
103→        return;
104→      }
105→
106→      spdlog::info("Discovered topic '{}' (type: '{}') in domain {}", topic_name, type_name, domain_id_);
107→
108→      source_.on_topic_discovered(topic_name, type_name, dynamic_type, oss.str(), domain_id_);
109→
110→    } catch (const std::exception& e) {
111→      spdlog::error("Exception in ParticipantListener on domain {}: {}", domain_id_, e.what());
112→    }
113→  }
114→
115→ private:
116→  FastDdsTopicSource& source_;
117→  int32_t domain_id_;
118→};
119→
120→// ---------------------------------------------------------------------------
121→// FastDdsTopicSource
122→// ---------------------------------------------------------------------------
123→FastDdsTopicSource::FastDdsTopicSource(const std::vector<int32_t>& domain_ids) {
124→  auto* factory = DomainParticipantFactory::get_instance();
125→
126→  for (int32_t domain_id : domain_ids) {
127→    spdlog::info("Creating DomainParticipant for domain {}", domain_id);
128→
129→    DomainParticipantQos pqos;
130→    pqos.name("pj_bridge_fastdds_" + std::to_string(domain_id));
131→    // TypeLookup service is enabled by default in Fast DDS 3.4
132→
133→    auto listener = std::make_shared<ParticipantListener>(*this, domain_id);
134→    listeners_.push_back(listener);
135→
136→    DomainParticipant* participant =
137→        factory->create_participant(domain_id, pqos, listener.get(), StatusMask::none());
138→
139→    if (!participant) {
140→      spdlog::error("Failed to create DomainParticipant for domain {}", domain_id);
141→      continue;
142→    }
143→
144→    participants_.emplace(domain_id, participant);
145→    spdlog::info("Topic discovery active on domain {}", domain_id);
146→  }
147→}
148→
149→FastDdsTopicSource::~FastDdsTopicSource() {
150→  auto* factory = DomainParticipantFactory::get_instance();
151→
152→  for (auto& [domain_id, participant] : participants_) {
153→    try {
154→      spdlog::debug("[shutdown] Deleting DomainParticipant for domain {}...", domain_id);
155→      // Remove listener before deletion to prevent callbacks during teardown
156→      participant->set_listener(nullptr);
157→      factory->delete_participant(participant);
158→      spdlog::debug("[shutdown] DomainParticipant for domain {} deleted", domain_id);
159→    } catch (const std::exception& e) {
160→      spdlog::warn("Error deleting participant for domain {}: {}", domain_id, e.what());
161→    } catch (...) {
162→      spdlog::warn("Unknown error deleting participant for domain {}", domain_id);
163→    }
164→  }
165→  listeners_.clear();
166→  spdlog::debug("[shutdown] ~FastDdsTopicSource complete");
167→}
168→
169→void FastDdsTopicSource::on_topic_discovered(
170→    const std::string& topic_name, const std::string& type_name,
171→    DynamicType::_ref_type dynamic_type, const std::string& schema_idl, int32_t domain_id) {
172→  std::unique_lock<std::shared_mutex> lock(mutex_);
173→
174→  if (topics_.find(topic_name) != topics_.end()) {
175→    return;
176→  }
177→
178→  topics_.emplace(topic_name, DiscoveredTopic{type_name, dynamic_type, schema_idl, domain_id});
179→  spdlog::info("Cached topic '{}' (type: '{}', domain: {})", topic_name, type_name, domain_id);
180→}
181→
182→std::vector<TopicInfo> FastDdsTopicSource::get_topics() {
183→  std::shared_lock<std::shared_mutex> lock(mutex_);
184→
185→  std::vector<TopicInfo> result;
186→  result.reserve(topics_.size());
187→
188→  for (const auto& [name, topic] : topics_) {
189→    result.push_back({name, topic.type_name});
190→  }
191→
192→  return result;
193→}
194→
195→std::string FastDdsTopicSource::get_schema(const std::string& topic_name) {
196→  std::shared_lock<std::shared_mutex> lock(mutex_);
197→
198→  auto it = topics_.find(topic_name);
199→  if (it == topics_.end()) {
200→    return "";
201→  }
202→
203→  return it->second.schema_idl;
204→}
205→
206→std::string FastDdsTopicSource::schema_encoding() const {
207→  return kSchemaEncodingOmgIdl;
208→}
209→
210→DynamicType::_ref_type FastDdsTopicSource::get_dynamic_type(const std::string& topic_name) const {
211→  std::shared_lock<std::shared_mutex> lock(mutex_);
212→
213→  auto it = topics_.find(topic_name);
214→  if (it == topics_.end()) {
215→    return nullptr;
216→  }
217→
218→  return it->second.dynamic_type;
219→}
220→
221→DomainParticipant* FastDdsTopicSource::get_participant(int32_t domain_id) const {
222→  std::shared_lock<std::shared_mutex> lock(mutex_);
223→
224→  auto it = participants_.find(domain_id);
225→  if (it == participants_.end()) {
226→    return nullptr;
227→  }
228→  return it->second;
229→}
230→
231→std::optional<int32_t> FastDdsTopicSource::get_domain_id(const std::string& topic_name) const {
232→  std::shared_lock<std::shared_mutex> lock(mutex_);
233→
234→  auto it = topics_.find(topic_name);
235→  if (it == topics_.end()) {
236→    return std::nullopt;
237→  }
238→
239→  return it->second.domain_id;
240→}
