51→bool TopicDiscovery::refresh() {
52→  try {
53→    discover_topics();
54→    return true;
55→  } catch (const std::exception& e) {
56→    RCLCPP_ERROR(node_->get_logger(), "Topic discovery refresh failed: %s", e.what());
57→    return false;
58→  }
59→}
