 28→class DdsTopicDiscovery::PublisherListener
 29→    : public dds::sub::NoOpDataReaderListener<dds::topic::PublicationBuiltinTopicData> {
 30→ public:
 31→  PublisherListener(DdsTopicDiscovery& discovery, int32_t domain_id) : discovery_(discovery), domain_id_(domain_id) {}
 32→
 33→  void on_data_available(dds::sub::DataReader<dds::topic::PublicationBuiltinTopicData>& reader) override {
 34→    try {
 35→      auto samples = reader.select().state(dds::sub::status::DataState::new_instance()).take();
 36→
 37→      for (const auto& sample : samples) {
 38→        if (!sample.info().valid()) {
 39→          continue;
 40→        }
 41→
 42→        std::string name_str = sample.data().topic_name().to_std_string();
 43→        const auto& type = sample.data().extensions().type();
 44→
 45→        if (!type) {
 46→          spdlog::debug("Topic '{}' discovered without type info in domain {}", name_str, domain_id_);
 47→          continue;
 48→        }
 49→
 50→        if (type->kind() != dds::core::xtypes::TypeKind::STRUCTURE_TYPE) {
 51→          spdlog::debug("Topic '{}' has non-struct type '{}', skipping", name_str, type->name());
 52→          continue;
 53→        }
 54→
 55→        auto struct_type = static_cast<const dds::core::xtypes::StructType&>(type.get());
 56→
 57→        rti::core::xtypes::DynamicTypePrintFormatProperty print_format{
 58→            0, false, rti::core::xtypes::DynamicTypePrintKind::idl, true};
 59→        std::string schema_idl = rti::core::xtypes::to_string(type.get(), print_format);
 60→
 61→        spdlog::info("Discovered topic '{}' (type: '{}') in domain {}", name_str, struct_type.name(), domain_id_);
 62→
 63→        discovery_.on_topic_discovered(name_str, struct_type, schema_idl, domain_id_);
 64→      }
 65→    } catch (const std::exception& e) {
 66→      spdlog::error("Exception in PublisherListener on domain {}: {}", domain_id_, e.what());
 67→    }
 68→  }
 69→
 70→ private:
 71→  DdsTopicDiscovery& discovery_;
 72→  int32_t domain_id_;
 73→};
