 75→DdsTopicDiscovery::DdsTopicDiscovery(const std::vector<int32_t>& domain_ids, const std::string& qos_profile_path) {
 76→  if (!qos_profile_path.empty()) {
 77→    rti::core::QosProviderParams params;
 78→    params.url_profile({qos_profile_path});
 79→    rti::core::default_qos_provider_params(params);
 80→    spdlog::info("Set default QoS profile from '{}'", qos_profile_path);
 81→  }
 82→
 83→  for (int32_t domain_id : domain_ids) {
 84→    spdlog::info("Creating DomainParticipant for domain {}", domain_id);
 85→
 86→    dds::domain::DomainParticipant participant(domain_id);
 87→    participants_.emplace(domain_id, participant);
 88→
 89→    auto listener = std::make_shared<PublisherListener>(*this, domain_id);
 90→    listeners_.push_back(listener);
 91→
 92→    dds::sub::Subscriber builtin_subscriber = dds::sub::builtin_subscriber(participant);
 93→    std::vector<dds::sub::DataReader<dds::topic::PublicationBuiltinTopicData>> readers;
 94→    dds::sub::find<dds::sub::DataReader<dds::topic::PublicationBuiltinTopicData>>(
 95→        builtin_subscriber, dds::topic::publication_topic_name(), std::back_inserter(readers));
 96→
 97→    if (readers.empty()) {
 98→      spdlog::error("No built-in publication DataReader found for domain {}", domain_id);
 99→      continue;
100→    }
101→
102→    readers[0].set_listener(listener);
103→    builtin_readers_.push_back(std::move(readers[0]));
104→
105→    spdlog::info("Topic discovery active on domain {}", domain_id);
106→  }
107→}
108→
109→DdsTopicDiscovery::~DdsTopicDiscovery() {
110→  spdlog::debug("[shutdown] ~DdsTopicDiscovery: clearing {} builtin readers", builtin_readers_.size());
111→  for (auto& reader : builtin_readers_) {
112→    try {
113→      reader.set_listener(nullptr);
114→    } catch (const std::exception& e) {
115→      spdlog::warn("Error clearing builtin reader listener: {}", e.what());
116→    } catch (...) {
117→      spdlog::warn("Unknown error clearing builtin reader listener");
118→    }
119→  }
120→  builtin_readers_.clear();
121→  listeners_.clear();
122→  spdlog::debug("[shutdown] ~DdsTopicDiscovery: builtin readers cleared");
123→
124→  for (auto& [domain_id, participant] : participants_) {
125→    try {
126→      spdlog::debug("[shutdown] Closing DomainParticipant for domain {}...", domain_id);
127→      participant.close();
128→      spdlog::debug("[shutdown] DomainParticipant for domain {} closed", domain_id);
129→    } catch (const std::exception& e) {
130→      spdlog::warn("Error closing participant for domain {}: {}", domain_id, e.what());
131→    } catch (...) {
132→      spdlog::warn("Unknown error closing participant for domain {}", domain_id);
133→    }
134→  }
135→  spdlog::debug("[shutdown] ~DdsTopicDiscovery complete");
136→}
137→
138→void DdsTopicDiscovery::on_topic_discovered(
139→    const std::string& topic_name, const dds::core::xtypes::StructType& struct_type, const std::string& schema_idl,
140→    int32_t domain_id) {
141→  std::unique_lock<std::shared_mutex> lock(mutex_);
142→
143→  if (topics_.find(topic_name) != topics_.end()) {
144→    return;
145→  }
146→
147→  topics_.emplace(topic_name, DiscoveredTopic{struct_type, schema_idl, domain_id});
148→  spdlog::info("Cached topic '{}' (type: '{}', domain: {})", topic_name, struct_type.name(), domain_id);
149→}
150→
151→std::vector<TopicInfo> DdsTopicDiscovery::get_topics() {
152→  std::shared_lock<std::shared_mutex> lock(mutex_);
153→
154→  std::vector<TopicInfo> result;
155→  result.reserve(topics_.size());
156→
157→  for (const auto& [name, topic] : topics_) {
158→    result.push_back({name, topic.struct_type.name()});
159→  }
160→
161→  return result;
162→}
163→
164→std::string DdsTopicDiscovery::get_schema(const std::string& topic_name) {
165→  std::shared_lock<std::shared_mutex> lock(mutex_);
166→
167→  auto it = topics_.find(topic_name);
