 25→
 26→class DdsSubscriptionManager::InternalReaderListener
 27→    : public dds::sub::NoOpDataReaderListener<dds::core::xtypes::DynamicData> {
 28→ public:
 29→  InternalReaderListener(const std::string& topic_name, DdsSubscriptionManager& manager)
 30→      : topic_name_(topic_name), manager_(manager) {}
 31→
 32→  void on_data_available(dds::sub::DataReader<dds::core::xtypes::DynamicData>& reader) override {
 33→    try {
 34→      auto samples = reader.take();
 35→
 36→      MessageCallback cb;
 37→      {
 38→        std::lock_guard<std::mutex> lock(manager_.mutex_);
 39→        cb = manager_.callback_;
 40→      }
 41→
 42→      if (!cb) {
 43→        return;
 44→      }
 45→
 46→      for (const auto& sample : samples) {
 47→        if (!sample.info().valid()) {
 48→          continue;
 49→        }
 50→
 51→        auto cdr_buffer = sample.data().get_cdr_buffer();
 52→        const auto* raw_data = reinterpret_cast<const std::byte*>(cdr_buffer.first);
 53→        uint32_t data_size = cdr_buffer.second;
 54→
 55→        auto cdr_data = std::make_shared<std::vector<std::byte>>(raw_data, raw_data + data_size);
 56→
 57→        const auto& source_ts = sample.info().source_timestamp();
 58→        uint64_t timestamp_ns = (static_cast<uint64_t>(source_ts.sec()) * 1'000'000'000ULL) + source_ts.nanosec();
 59→
 60→        cb(topic_name_, std::move(cdr_data), timestamp_ns);
 61→      }
 62→    } catch (const std::exception& e) {
 63→      spdlog::error("Exception in DataReaderListener for '{}': {}", topic_name_, e.what());
 64→    }
 65→  }
 66→
 67→ private:
 68→  std::string topic_name_;
 69→  DdsSubscriptionManager& manager_;
 70→};
