 20→#include <spdlog/spdlog.h>
 21→
 22→#include <CLI/CLI.hpp>
 23→#include <atomic>
 24→#include <chrono>
 25→#include <csignal>
 26→#include <string>
 27→#include <thread>
 28→#include <vector>
 29→
 30→#include "pj_bridge/bridge_server.hpp"
 31→#include "pj_bridge/middleware/websocket_middleware.hpp"
 32→#include "pj_bridge_rti/dds_subscription_manager.hpp"
 33→#include "pj_bridge_rti/dds_topic_discovery.hpp"
 34→
 35→namespace {
 36→std::atomic<bool> g_shutdown{false};
 37→
 38→void signal_handler(int /*signum*/) {
 39→  g_shutdown.store(true);
 40→}
 41→}  // namespace
 42→
 43→int main(int argc, char* argv[]) {
 44→  CLI::App app{"pj_bridge RTI DDS Backend"};
 45→
 46→  std::vector<int32_t> domain_ids;
 47→  int port = 8080;
 48→  double publish_rate = 50.0;
 49→  double session_timeout = 10.0;
 50→  std::string qos_profile;
 51→  std::string log_level = "info";
 52→  bool stats_enabled = false;
 53→
 54→  app.add_option("--domains,-d", domain_ids, "DDS domain IDs")->required()->expected(1, -1);
 55→  app.add_option("--port,-p", port, "WebSocket port")->default_val(8080)->check(CLI::Range(1, 65535));
 56→  app.add_option("--publish-rate", publish_rate, "Aggregation publish rate in Hz")->default_val(50.0);
 57→  app.add_option("--session-timeout", session_timeout, "Session timeout in seconds")->default_val(10.0);
 58→  app.add_option("--qos-profile", qos_profile, "QoS profile XML file path");
 59→  app.add_option("--log-level", log_level, "Log level (trace, debug, info, warn, error)")->default_val("info");
 60→  app.add_flag("--stats", stats_enabled, "Print statistics every 5 seconds");
 61→
 62→  CLI11_PARSE(app, argc, argv);
 63→
 64→  spdlog::set_level(spdlog::level::from_str(log_level));
 65→
 66→  spdlog::info("pj_bridge (RTI DDS backend) starting...");
 67→  spdlog::info("  Domains: {}", fmt::join(domain_ids, ", "));
 68→  spdlog::info("  Port: {}", port);
 69→  spdlog::info("  Publish rate: {:.1f} Hz", publish_rate);
 70→  spdlog::info("  Session timeout: {:.1f} s", session_timeout);
 71→  if (!qos_profile.empty()) {
 72→    spdlog::info("  QoS profile: {}", qos_profile);
 73→  }
 74→
 75→  std::signal(SIGINT, signal_handler);
 76→  std::signal(SIGTERM, signal_handler);
 77→
 78→  try {
 79→    // Create DDS components (implement TopicSourceInterface and SubscriptionManagerInterface directly)
 80→    auto topic_source = std::make_shared<pj_bridge::DdsTopicDiscovery>(domain_ids, qos_profile);
 81→    auto sub_manager = std::make_shared<pj_bridge::DdsSubscriptionManager>(*topic_source);
 82→
 83→    // Create WebSocket middleware
 84→    auto middleware = std::make_shared<pj_bridge::WebSocketMiddleware>();
 85→
 86→    // Create bridge server
 87→    pj_bridge::BridgeServer server(topic_source, sub_manager, middleware, port, session_timeout, publish_rate);
 88→
 89→    if (!server.initialize()) {
 90→      spdlog::error("Failed to initialize bridge server");
 91→      return 1;
 92→    }
 93→
 94→    spdlog::info("Bridge server initialized, entering event loop");
 95→
 96→    // Event loop
 97→    using clock = std::chrono::steady_clock;
 98→    auto publish_interval =
 99→        std::chrono::duration_cast<std::chrono::nanoseconds>(std::chrono::duration<double>(1.0 / publish_rate));
100→    auto last_publish = clock::now();
101→    auto last_timeout_check = clock::now();
102→    auto last_stats_print = clock::now();
103→    uint64_t prev_bytes_published = 0;
104→
105→    while (!g_shutdown.load()) {
106→      server.process_requests();
107→
108→      auto now = clock::now();
109→
110→      if (now - last_publish >= publish_interval) {
111→        server.publish_aggregated_messages();
112→        last_publish += publish_interval;
113→      }
114→
115→      if (now - last_timeout_check >= std::chrono::seconds(1)) {
116→        server.check_session_timeouts();
117→        last_timeout_check = now;
118→      }
119→
120→      if (stats_enabled && now - last_stats_print >= std::chrono::seconds(5)) {
121→        auto elapsed = std::chrono::duration<double>(now - last_stats_print).count();
122→        auto snapshot = server.snapshot_and_reset_stats();
123→
124→        std::string stats_msg = "=== Stats ===\n  DDS receive rates:";
125→        if (snapshot.topic_receive_counts.empty()) {
126→          stats_msg += "\n    (no subscriptions)";
127→        } else {
128→          for (const auto& [topic, count] : snapshot.topic_receive_counts) {
129→            stats_msg += fmt::format("\n    {}: {:.1f} msg/s", topic, static_cast<double>(count) / elapsed);
130→          }
131→        }
132→
133→        stats_msg +=
134→            fmt::format("\n  Publish frequency: {:.1f} Hz", static_cast<double>(snapshot.publish_cycles) / elapsed);
135→        uint64_t delta_bytes = snapshot.total_bytes_published - prev_bytes_published;
136→        prev_bytes_published = snapshot.total_bytes_published;
137→        stats_msg +=
138→            fmt::format("\n  Sent: {:.2f} MB/s", static_cast<double>(delta_bytes) / elapsed / (1024.0 * 1024.0));
139→
140→        spdlog::info(stats_msg);
141→        last_stats_print = now;
142→      }
143→
144→      std::this_thread::sleep_for(std::chrono::milliseconds(1));
145→    }
146→
147→    spdlog::info("Shutting down...");
148→
149→    // Explicit ordered shutdown to avoid use-after-free:
150→    // 1. Clear DDS message callback
151→    spdlog::debug("[shutdown] Clearing DDS message callback...");
152→    sub_manager->set_message_callback(nullptr);
153→    // 2. Unsubscribe all DDS readers
154→    spdlog::debug("[shutdown] Unsubscribing all DDS readers...");
155→    sub_manager->unsubscribe_all();
156→    // 3. Shutdown WebSocket server
157→    spdlog::debug("[shutdown] Shutting down WebSocket middleware...");
158→    middleware->shutdown();
159→    spdlog::debug("[shutdown] Cleanup complete, exiting scope (destructors will run)...");
160→  } catch (const std::exception& e) {
161→    spdlog::error("Fatal error: {}", e.what());
162→    return 1;
163→  }
164→
165→  return 0;
166→}
