 32→std::string SchemaExtractor::get_message_definition(const std::string& message_type) {
 33→  {
 34→    std::shared_lock<std::shared_mutex> lock(cache_mutex_);
 35→    auto it = definition_cache_.find(message_type);
 36→    if (it != definition_cache_.end()) {
 37→      return it->second;
 38→    }
 39→  }
 40→
 41→  std::string package_name;
 42→  std::string type_name;
 43→
 44→  if (!parse_message_type(message_type, package_name, type_name)) {
 45→    return "";
 46→  }
 47→
 48→  std::ostringstream result;
 49→  std::unordered_set<std::string> processed_types;
 50→
 51→  if (!build_message_definition_recursive(package_name, type_name, result, processed_types, true)) {
 52→    return "";
 53→  }
 54→
 55→  std::string definition = result.str();
 56→
 57→  {
 58→    std::unique_lock<std::shared_mutex> lock(cache_mutex_);
 59→    definition_cache_[message_type] = definition;
 60→  }
 61→
 62→  return definition;
 63→}
 64→
 65→bool SchemaExtractor::build_message_definition_recursive(
 66→    const std::string& package_name, const std::string& type_name, std::ostringstream& output,
 67→    std::unordered_set<std::string>& processed_types, bool is_root) const {
 68→  const std::string full_type = package_name + "/" + type_name;
 69→
 70→  std::string msg_content;
 71→  {
 72→    std::shared_lock<std::shared_mutex> lock(cache_mutex_);
 73→    auto it = msg_file_cache_.find(full_type);
 74→    if (it != msg_file_cache_.end()) {
 75→      msg_content = it->second;
 76→    }
 77→  }
 78→
 79→  if (msg_content.empty()) {
 80→    std::string package_share_dir;
 81→    try {
 82→      package_share_dir = ament_index_cpp::get_package_share_directory(package_name);
 83→    } catch (const std::exception& e) {
 84→      return false;
 85→    }
 86→
 87→    std::string msg_file_path = package_share_dir + "/msg/" + type_name + ".msg";
 88→
 89→    std::ifstream msg_file(msg_file_path);
 90→    if (!msg_file.is_open()) {
 91→      return false;
 92→    }
 93→
 94→    std::ostringstream content_stream;
 95→    std::string line;
 96→    while (std::getline(msg_file, line)) {
 97→      content_stream << line << "\n";
 98→    }
 99→    msg_content = content_stream.str();
100→
101→    {
102→      std::unique_lock<std::shared_mutex> lock(cache_mutex_);
103→      msg_file_cache_[full_type] = msg_content;
104→    }
105→  }
106→
107→  if (!is_root) {
108→    output << "\n================================================================================\n";
109→    output << "MSG: " << full_type << "\n";
110→  }
111→
112→  std::istringstream msg_stream(msg_content);
113→  std::string line;
114→  std::vector<std::string> nested_types;
115→
116→  while (std::getline(msg_stream, line)) {
117→    output << line << "\n";
118→
119→    std::istringstream line_stream(line);
120→    std::string first_word;
121→    line_stream >> first_word;
122→
123→    if (first_word.empty() || first_word[0] == '#') {
124→      continue;
125→    }
126→
127→    std::string nested_package;
128→    std::string nested_type;
129→
130→    if (first_word.find('/') != std::string::npos) {
131→      size_t slash_pos = first_word.find('/');
132→      nested_package = first_word.substr(0, slash_pos);
133→      nested_type = first_word.substr(slash_pos + 1);
134→
135→      size_t bracket_pos = nested_type.find('[');
136→      if (bracket_pos != std::string::npos) {
137→        nested_type = nested_type.substr(0, bracket_pos);
138→      }
139→    } else {
140→      std::string base_type = first_word;
141→      size_t bracket_pos = base_type.find('[');
142→      if (bracket_pos != std::string::npos) {
143→        base_type = base_type.substr(0, bracket_pos);
144→      }
145→
146→      static const std::unordered_set<std::string> kBuiltinTypes = {"bool",   "byte",  "char",   "float32", "float64",
147→                                                                    "int8",   "uint8", "int16",  "uint16",  "int32",
148→                                                                    "uint32", "int64", "uint64", "string",  "wstring"};
149→      bool is_builtin = kBuiltinTypes.count(base_type) > 0;
150→
151→      if (!is_builtin) {
152→        nested_package = package_name;
153→        nested_type = base_type;
154→      }
155→    }
156→
157→    if (!nested_type.empty()) {
158→      std::string full_nested_type = nested_package + "/" + nested_type;
159→      if (processed_types.find(full_nested_type) == processed_types.end()) {
160→        processed_types.insert(full_nested_type);
161→        nested_types.push_back(full_nested_type);
162→      }
163→    }
164→  }
165→
166→  if (nested_types.size() >= 2) {
167→    if (nested_types.at(0) == "std_msgs/Header") {
168→      nested_types.push_back(nested_types.at(0));
169→      nested_types.erase(nested_types.begin());
170→    }
171→  }
172→
173→  for (const auto& nested_full_type : nested_types) {
174→    size_t slash_pos = nested_full_type.find('/');
175→    std::string nested_pkg = nested_full_type.substr(0, slash_pos);
176→    std::string nested_typ = nested_full_type.substr(slash_pos + 1);
177→
178→    if (!build_message_definition_recursive(nested_pkg, nested_typ, output, processed_types, false)) {
179→      return false;
180→    }
181→  }
182→
183→  return true;
184→}
185→
186→bool SchemaExtractor::parse_message_type(
187→    const std::string& message_type, std::string& library_name, std::string& type_name) const {
188→  size_t first_slash = message_type.find('/');
189→  if (first_slash == std::string::npos) {
190→    return false;
191→  }
192→
193→  size_t second_slash = message_type.find('/', first_slash + 1);
194→  if (second_slash == std::string::npos) {
195→    return false;
196→  }
197→
198→  library_name = message_type.substr(0, first_slash);
199→  type_name = message_type.substr(second_slash + 1);
200→
201→  return true;
202→}
203→
204→std::string remove_comments_from_schema(const std::string& schema) {
205→  std::istringstream input(schema);
206→  std::ostringstream output;
207→  std::string line;
208→
209→  while (std::getline(input, line)) {
210→    size_t comment_pos = line.find('#');
211→
212→    if (comment_pos != std::string::npos) {
213→      std::string before_comment = line.substr(0, comment_pos);
214→
215→      size_t end = before_comment.find_last_not_of(" \t\r\n");
216→      if (end != std::string::npos) {
217→        before_comment = before_comment.substr(0, end + 1);
218→      } else {
219→        before_comment = "";
220→      }
221→
222→      if (!before_comment.empty()) {
223→        output << before_comment << "\n";
224→      }
225→    } else {
226→      output << line << "\n";
227→    }
228→  }
229→
230→  return output.str();
231→}
