35→const std::unordered_set<std::string> kStrippableTypes = {
36→    "sensor_msgs/msg/Image",     "sensor_msgs/msg/CompressedImage", "sensor_msgs/msg/PointCloud2",
37→    "sensor_msgs/msg/LaserScan", "nav_msgs/msg/OccupancyGrid",
38→};
39→
40→template <typename MsgT, typename StripFn>
41→rclcpp::SerializedMessage strip_and_reserialize(const rclcpp::SerializedMessage& input, StripFn strip_fn) {
42→  rclcpp::Serialization<MsgT> serializer;
43→  MsgT msg;
44→  serializer.deserialize_message(&input, &msg);
45→  strip_fn(msg);
46→  rclcpp::SerializedMessage output;
47→  serializer.serialize_message(&msg, &output);
48→  return output;
49→}
50→
51→}  // namespace
52→
53→bool MessageStripper::should_strip(const std::string& message_type) {
54→  return kStrippableTypes.find(message_type) != kStrippableTypes.end();
55→}
56→
57→rclcpp::SerializedMessage MessageStripper::strip(
58→    const std::string& message_type, const rclcpp::SerializedMessage& input) {
59→  if (message_type == "sensor_msgs/msg/Image") {
60→    return strip_and_reserialize<sensor_msgs::msg::Image>(input, [](auto& m) { m.data = {0}; });
61→  }
62→  if (message_type == "sensor_msgs/msg/CompressedImage") {
63→    return strip_and_reserialize<sensor_msgs::msg::CompressedImage>(input, [](auto& m) { m.data = {0}; });
64→  }
65→  if (message_type == "sensor_msgs/msg/PointCloud2") {
66→    return strip_and_reserialize<sensor_msgs::msg::PointCloud2>(input, [](auto& m) { m.data = {0}; });
67→  }
68→  if (message_type == "sensor_msgs/msg/LaserScan") {
69→    return strip_and_reserialize<sensor_msgs::msg::LaserScan>(input, [](auto& m) {
70→      m.ranges = {0.0f};
71→      m.intensities = {0.0f};
72→    });
73→  }
74→  if (message_type == "nav_msgs/msg/OccupancyGrid") {
75→    return strip_and_reserialize<nav_msgs::msg::OccupancyGrid>(input, [](auto& m) { m.data = {0}; });
76→  }
77→
78→  throw std::runtime_error("strip() not implemented for type: " + message_type);
79→}
