 40→// ---------------------------------------------------------------------------
 41→// ParticipantListener — handles on_data_writer_discovery callbacks
 42→// ---------------------------------------------------------------------------
 43→class FastDdsTopicSource::ParticipantListener : public DomainParticipantListener {
 44→ public:
 45→  ParticipantListener(FastDdsTopicSource& source, int32_t domain_id) : source_(source), domain_id_(domain_id) {}
 46→
 47→  void on_data_writer_discovery(
 48→      DomainParticipant* /*participant*/, WriterDiscoveryStatus reason,
 49→      const PublicationBuiltinTopicData& info, bool& should_be_ignored) override {
 50→    should_be_ignored = false;
 51→
 52→    if (reason != WriterDiscoveryStatus::DISCOVERED_WRITER) {
 53→      return;
 54→    }
 55→
 56→    try {
 57→      std::string topic_name(info.topic_name);
 58→
 59→      // Skip if already cached (fast check before heavy TypeObject work)
 60→      {
 61→        std::shared_lock<std::shared_mutex> lock(source_.mutex_);
 62→        if (source_.topics_.count(topic_name) > 0) {
 63→          return;
 64→        }
 65→      }
 66→
 67→      // Get TypeObject from the global registry via the type identifier in the
 68→      // discovery info's TypeInformation
 69→      xtypes::TypeObject type_object;
 70→      auto& registry = DomainParticipantFactory::get_instance()->type_object_registry();
 71→      const auto& type_id =
 72→          info.type_information.type_information.complete().typeid_with_size().type_id();
 73→
 74→      if (RETCODE_OK != registry.get_type_object(type_id, type_object)) {
 75→        spdlog::debug(
 76→            "Topic '{}' discovered but TypeObject not yet in registry (domain {})", topic_name, domain_id_);
 77→        return;
 78→      }
 79→
 80→      // Build DynamicType
 81→      auto builder = DynamicTypeBuilderFactory::get_instance()->create_type_w_type_object(type_object);
 82→      if (!builder) {
 83→        spdlog::warn("Failed to create DynamicTypeBuilder for '{}' (domain {})", topic_name, domain_id_);
 84→        return;
 85→      }
 86→      DynamicType::_ref_type dynamic_type = builder->build();
 87→      if (!dynamic_type) {
 88→        spdlog::warn("Failed to build DynamicType for '{}' (domain {})", topic_name, domain_id_);
 89→        return;
 90→      }
 91→
 92→      // Only accept struct types (like RTI backend)
 93→      if (dynamic_type->get_kind() != TK_STRUCTURE) {
 94→        spdlog::debug(
 95→            "Topic '{}' has non-struct type '{}', skipping", topic_name, std::string(dynamic_type->get_name()));
 96→        return;
 97→      }
 98→
 99→      // Generate OMG IDL schema
100→      std::ostringstream oss;
101→      if (RETCODE_OK != idl_serialize(dynamic_type, oss)) {
102→        spdlog::warn("Failed to serialize IDL for '{}' (domain {})", topic_name, domain_id_);
103→        return;
104→      }
105→
106→      spdlog::info(
107→          "Discovered topic '{}' (type: '{}') in domain {}", topic_name, std::string(dynamic_type->get_name()),
108→          domain_id_);
109→
110→      source_.on_topic_discovered(topic_name, dynamic_type, oss.str(), domain_id_);
111→
112→    } catch (const std::exception& e) {
113→      spdlog::error("Exception in ParticipantListener on domain {}: {}", domain_id_, e.what());
114→    }
115→  }
116→
117→ private:
118→  FastDdsTopicSource& source_;
119→  int32_t domain_id_;
120→};
