122→// ---------------------------------------------------------------------------
123→// FastDdsTopicSource
124→// ---------------------------------------------------------------------------
125→FastDdsTopicSource::FastDdsTopicSource(const std::vector<int32_t>& domain_ids) {
126→  auto* factory = DomainParticipantFactory::get_instance();
127→
128→  for (int32_t domain_id : domain_ids) {
129→    spdlog::info("Creating DomainParticipant for domain {}", domain_id);
130→
131→    DomainParticipantQos pqos;
132→    pqos.name("pj_bridge_fastdds_" + std::to_string(domain_id));
133→    // TypeLookup service is enabled by default in Fast DDS 3.4
134→
135→    auto listener = std::make_shared<ParticipantListener>(*this, domain_id);
136→    listeners_.push_back(listener);
137→
138→    DomainParticipant* participant =
139→        factory->create_participant(domain_id, pqos, listener.get(), StatusMask::none());
140→
141→    if (!participant) {
142→      spdlog::error("Failed to create DomainParticipant for domain {}", domain_id);
143→      continue;
144→    }
145→
146→    participants_.emplace(domain_id, participant);
147→    spdlog::info("Topic discovery active on domain {}", domain_id);
148→  }
149→}
150→
151→FastDdsTopicSource::~FastDdsTopicSource() {
152→  auto* factory = DomainParticipantFactory::get_instance();
153→
154→  for (auto& [domain_id, participant] : participants_) {
155→    try {
156→      spdlog::debug("[shutdown] Deleting DomainParticipant for domain {}...", domain_id);
157→      // Remove listener before deletion to prevent callbacks during teardown
158→      participant->set_listener(nullptr);
159→      factory->delete_participant(participant);
160→      spdlog::debug("[shutdown] DomainParticipant for domain {} deleted", domain_id);
161→    } catch (const std::exception& e) {
162→      spdlog::warn("Error deleting participant for domain {}: {}", domain_id, e.what());
163→    } catch (...) {
164→      spdlog::warn("Unknown error deleting participant for domain {}", domain_id);
165→    }
166→  }
167→  listeners_.clear();
168→  spdlog::debug("[shutdown] ~FastDdsTopicSource complete");
169→}
