171→void FastDdsTopicSource::on_topic_discovered(
172→    const std::string& topic_name, DynamicType::_ref_type dynamic_type, const std::string& schema_idl,
173→    int32_t domain_id) {
174→  std::unique_lock<std::shared_mutex> lock(mutex_);
175→
176→  if (topics_.find(topic_name) != topics_.end()) {
177→    return;
178→  }
179→
180→  topics_.emplace(topic_name, DiscoveredTopic{dynamic_type, schema_idl, domain_id});
181→  spdlog::info("Cached topic '{}' (type: '{}', domain: {})", topic_name, std::string(dynamic_type->get_name()),
182→               domain_id);
183→}
