42→// SubscriptionManagerInterface implementation for eProsima Fast DDS.
43→//
44→// Creates DataReaders with DynamicPubSubType for each subscribed topic.
45→// Incoming samples are deserialized into DynamicData and re-serialized to
46→// extract raw CDR bytes, which are passed to the message callback.
47→// Subscriptions are reference-counted.
48→class FastDdsSubscriptionManager : public SubscriptionManagerInterface {
49→ public:
50→  explicit FastDdsSubscriptionManager(FastDdsTopicSource& topic_source);
51→  ~FastDdsSubscriptionManager() override;
52→
53→  FastDdsSubscriptionManager(const FastDdsSubscriptionManager&) = delete;
54→  FastDdsSubscriptionManager& operator=(const FastDdsSubscriptionManager&) = delete;
55→
56→  void set_message_callback(MessageCallback callback) override;
57→  bool subscribe(const std::string& topic_name, const std::string& topic_type) override;
58→  bool unsubscribe(const std::string& topic_name) override;
59→  void unsubscribe_all() override;
60→
61→ private:
62→  class InternalReaderListener;
63→
64→  struct SubscriptionInfo {
65→    eprosima::fastdds::dds::DomainParticipant* participant;
66→    eprosima::fastdds::dds::Subscriber* subscriber;
67→    eprosima::fastdds::dds::Topic* topic;
68→    eprosima::fastdds::dds::DataReader* reader;
69→    std::shared_ptr<InternalReaderListener> listener;
70→    size_t reference_count;
71→  };
72→
73→  void close_subscription(const std::string& topic_name, SubscriptionInfo& info);
74→
75→  FastDdsTopicSource& topic_source_;
76→  MessageCallback callback_;
77→  mutable std::mutex mutex_;
78→  std::unordered_map<std::string, SubscriptionInfo> subscriptions_;
79→};
