 38→// ---------------------------------------------------------------------------
 39→// InternalReaderListener
 40→// ---------------------------------------------------------------------------
 41→class FastDdsSubscriptionManager::InternalReaderListener : public DataReaderListener {
 42→ public:
 43→  InternalReaderListener(
 44→      const std::string& topic_name, FastDdsSubscriptionManager& manager, DynamicType::_ref_type dynamic_type)
 45→      : topic_name_(topic_name), manager_(manager), dynamic_type_(dynamic_type), pub_sub_type_(dynamic_type) {}
 46→
 47→  void on_data_available(DataReader* reader) override {
 48→    try {
 49→      MessageCallback cb;
 50→      {
 51→        std::lock_guard<std::mutex> lock(manager_.mutex_);
 52→        cb = manager_.callback_;
 53→      }
 54→
 55→      if (!cb) {
 56→        return;
 57→      }
 58→
 59→      DynamicData::_ref_type data = DynamicDataFactory::get_instance()->create_data(dynamic_type_);
 60→      SampleInfo info;
 61→
 62→      while (RETCODE_OK == reader->take_next_sample(&data, &info)) {
 63→        if (!info.valid_data) {
 64→          continue;
 65→        }
 66→
 67→        // Re-serialize DynamicData to get raw CDR bytes
 68→        uint32_t size = pub_sub_type_.calculate_serialized_size(
 69→            &data, DataRepresentationId_t::XCDR2_DATA_REPRESENTATION);
 70→        SerializedPayload_t payload(size);
 71→        if (!pub_sub_type_.serialize(&data, payload, DataRepresentationId_t::XCDR2_DATA_REPRESENTATION)) {
 72→          spdlog::warn("Failed to serialize DynamicData for '{}'", topic_name_);
 73→          continue;
 74→        }
 75→
 76→        auto cdr_data = std::make_shared<std::vector<std::byte>>(payload.length);
 77→        std::memcpy(cdr_data->data(), payload.data, payload.length);
 78→
 79→        uint64_t timestamp_ns = static_cast<uint64_t>(info.source_timestamp.seconds()) * 1'000'000'000ULL +
 80→                                info.source_timestamp.nanosec();
 81→
 82→        cb(topic_name_, std::move(cdr_data), timestamp_ns);
 83→      }
 84→    } catch (const std::exception& e) {
 85→      spdlog::error("Exception in DataReaderListener for '{}': {}", topic_name_, e.what());
 86→    }
 87→  }
 88→
 89→ private:
 90→  std::string topic_name_;
 91→  FastDdsSubscriptionManager& manager_;
 92→  DynamicType::_ref_type dynamic_type_;
 93→  DynamicPubSubType pub_sub_type_;
 94→};
