111→bool FastDdsSubscriptionManager::subscribe(const std::string& topic_name, const std::string& /*topic_type*/) {
112→  std::lock_guard<std::mutex> lock(mutex_);
113→
114→  auto it = subscriptions_.find(topic_name);
115→  if (it != subscriptions_.end()) {
116→    it->second.reference_count++;
117→    spdlog::debug("Incremented ref count for '{}' to {}", topic_name, it->second.reference_count);
118→    return true;
119→  }
120→
121→  auto dynamic_type = topic_source_.get_dynamic_type(topic_name);
122→  if (!dynamic_type) {
123→    spdlog::error("Topic '{}' not found in discovery", topic_name);
124→    return false;
125→  }
126→
127→  auto domain_id_opt = topic_source_.get_domain_id(topic_name);
128→  if (!domain_id_opt) {
129→    spdlog::error("No domain ID for topic '{}'", topic_name);
130→    return false;
131→  }
132→
133→  auto* participant = topic_source_.get_participant(*domain_id_opt);
134→  if (!participant) {
135→    spdlog::error("No participant for domain {}", *domain_id_opt);
136→    return false;
137→  }
138→
139→  try {
140→    // Register the DynamicType with the participant
141→    TypeSupport type_support(new DynamicPubSubType(dynamic_type));
142→    type_support.register_type(participant);
143→
144→    // Create Topic
145→    Topic* topic = participant->create_topic(topic_name, type_support.get_type_name(), TOPIC_QOS_DEFAULT);
146→    if (!topic) {
147→      spdlog::error("Failed to create topic for '{}'", topic_name);
148→      return false;
149→    }
150→
151→    // Create Subscriber
152→    Subscriber* subscriber = participant->create_subscriber(SUBSCRIBER_QOS_DEFAULT);
153→    if (!subscriber) {
154→      participant->delete_topic(topic);
155→      spdlog::error("Failed to create subscriber for '{}'", topic_name);
156→      return false;
157→    }
158→
159→    // Create DataReader with listener
160→    auto listener = std::make_shared<InternalReaderListener>(topic_name, *this, dynamic_type);
161→    DataReader* reader = subscriber->create_datareader(topic, DATAREADER_QOS_DEFAULT, listener.get());
162→    if (!reader) {
163→      participant->delete_subscriber(subscriber);
164→      participant->delete_topic(topic);
165→      spdlog::error("Failed to create datareader for '{}'", topic_name);
166→      return false;
167→    }
168→
169→    subscriptions_.emplace(
170→        topic_name,
171→        SubscriptionInfo{participant, subscriber, topic, reader, listener, 1});
172→
173→    spdlog::info(
174→        "Subscribed to '{}' (type: '{}', domain: {})", topic_name, type_support.get_type_name(), *domain_id_opt);
175→    return true;
176→  } catch (const std::exception& e) {
177→    spdlog::error("Failed to subscribe to '{}': {}", topic_name, e.what());
178→    return false;
179→  }
180→}
181→
182→bool FastDdsSubscriptionManager::unsubscribe(const std::string& topic_name) {
183→  SubscriptionInfo to_close{};
184→  bool should_close = false;
185→
186→  {
187→    std::lock_guard<std::mutex> lock(mutex_);
188→
189→    auto it = subscriptions_.find(topic_name);
190→    if (it == subscriptions_.end()) {
191→      return false;
192→    }
193→
194→    if (it->second.reference_count == 0) {
195→      return false;
196→    }
197→
198→    it->second.reference_count--;
199→    spdlog::debug("Decremented ref count for '{}' to {}", topic_name, it->second.reference_count);
200→
201→    if (it->second.reference_count == 0) {
202→      to_close = std::move(it->second);
203→      should_close = true;
204→      subscriptions_.erase(it);
205→    }
206→  }
207→
208→  // Close DDS entities outside lock to avoid deadlock
209→  if (should_close) {
210→    close_subscription(topic_name, to_close);
211→    spdlog::info("Unsubscribed from '{}' (reader destroyed)", topic_name);
212→  }
213→
214→  return true;
215→}
216→
217→void FastDdsSubscriptionManager::unsubscribe_all() {
218→  std::unordered_map<std::string, SubscriptionInfo> to_close;
219→
220→  {
221→    std::lock_guard<std::mutex> lock(mutex_);
222→    to_close.swap(subscriptions_);
223→  }
224→
225→  spdlog::debug("[shutdown] unsubscribe_all: {} subscriptions to close", to_close.size());
226→  for (auto& [name, info] : to_close) {
227→    spdlog::debug("[shutdown] Closing reader for '{}'...", name);
228→    close_subscription(name, info);
229→    spdlog::debug("[shutdown] Closed '{}'", name);
230→  }
231→  spdlog::debug("[shutdown] unsubscribe_all complete");
232→}
233→
234→void FastDdsSubscriptionManager::close_subscription(const std::string& topic_name, SubscriptionInfo& info) {
235→  try {
236→    info.reader->set_listener(nullptr);
237→    info.subscriber->delete_datareader(info.reader);
238→    info.participant->delete_subscriber(info.subscriber);
239→    info.participant->delete_topic(info.topic);
240→  } catch (const std::exception& e) {
241→    spdlog::warn("Error cleaning up reader for '{}': {}", topic_name, e.what());
242→  } catch (...) {
243→    spdlog::warn("Unknown error cleaning up reader for '{}'", topic_name);
244→  }
245→}
