 20→#include <spdlog/spdlog.h>
 21→
 22→#include <CLI/CLI.hpp>
 23→#include <atomic>
 24→#include <chrono>
 25→#include <csignal>
 26→#include <string>
 27→#include <thread>
 28→#include <vector>
 29→
 30→#include "pj_bridge/bridge_server.hpp"
 31→#include "pj_bridge/middleware/websocket_middleware.hpp"
 32→#include "pj_bridge_fastdds/fastdds_subscription_manager.hpp"
 33→#include "pj_bridge_fastdds/fastdds_topic_source.hpp"
 34→
 35→namespace {
 36→std::atomic<bool> g_shutdown{false};
 37→
 38→void signal_handler(int /*signum*/) {
 39→  g_shutdown.store(true);
 40→}
 41→}  // namespace
 42→
 43→int main(int argc, char* argv[]) {
 44→  CLI::App app{"pj_bridge eProsima FastDDS Backend"};
 45→
 46→  std::vector<int32_t> domain_ids;
 47→  int port = 8080;
 48→  double publish_rate = 50.0;
 49→  double session_timeout = 10.0;
 50→  std::string log_level = "info";
 51→  bool stats_enabled = false;
 52→
 53→  app.add_option("--domains,-d", domain_ids, "DDS domain IDs")->required()->expected(1, -1);
 54→  app.add_option("--port,-p", port, "WebSocket port")->default_val(8080)->check(CLI::Range(1, 65535));
 55→  app.add_option("--publish-rate", publish_rate, "Aggregation publish rate in Hz")->default_val(50.0);
 56→  app.add_option("--session-timeout", session_timeout, "Session timeout in seconds")->default_val(10.0);
 57→  app.add_option("--log-level", log_level, "Log level (trace, debug, info, warn, error)")->default_val("info");
 58→  app.add_flag("--stats", stats_enabled, "Print statistics every 5 seconds");
 59→
 60→  CLI11_PARSE(app, argc, argv);
 61→
 62→  spdlog::set_level(spdlog::level::from_str(log_level));
 63→
 64→  spdlog::info("pj_bridge (FastDDS backend) starting...");
 65→  spdlog::info("  Domains: {}", fmt::join(domain_ids, ", "));
 66→  spdlog::info("  Port: {}", port);
 67→  spdlog::info("  Publish rate: {:.1f} Hz", publish_rate);
 68→  spdlog::info("  Session timeout: {:.1f} s", session_timeout);
 69→
 70→  std::signal(SIGINT, signal_handler);
 71→  std::signal(SIGTERM, signal_handler);
 72→
 73→  try {
 74→    // Create FastDDS components (directly implement the interfaces — no adapter layer)
 75→    auto topic_source = std::make_shared<pj_bridge::FastDdsTopicSource>(domain_ids);
 76→    auto sub_manager = std::make_shared<pj_bridge::FastDdsSubscriptionManager>(*topic_source);
 77→
 78→    // Create WebSocket middleware
 79→    auto middleware = std::make_shared<pj_bridge::WebSocketMiddleware>();
 80→
 81→    // Create bridge server
 82→    pj_bridge::BridgeServer server(topic_source, sub_manager, middleware, port, session_timeout, publish_rate);
 83→
 84→    if (!server.initialize()) {
 85→      spdlog::error("Failed to initialize bridge server");
 86→      return 1;
 87→    }
 88→
 89→    spdlog::info("Bridge server initialized, entering event loop");
 90→
 91→    // Event loop
 92→    using clock = std::chrono::steady_clock;
 93→    auto publish_interval =
 94→        std::chrono::duration_cast<std::chrono::nanoseconds>(std::chrono::duration<double>(1.0 / publish_rate));
 95→    auto last_publish = clock::now();
 96→    auto last_timeout_check = clock::now();
 97→    auto last_stats_print = clock::now();
 98→    uint64_t prev_bytes_published = 0;
 99→
100→    while (!g_shutdown.load()) {
101→      server.process_requests();
102→
103→      auto now = clock::now();
104→
105→      if (now - last_publish >= publish_interval) {
106→        server.publish_aggregated_messages();
107→        last_publish += publish_interval;
108→      }
109→
110→      if (now - last_timeout_check >= std::chrono::seconds(1)) {
111→        server.check_session_timeouts();
112→        last_timeout_check = now;
113→      }
114→
115→      if (stats_enabled && now - last_stats_print >= std::chrono::seconds(5)) {
116→        auto elapsed = std::chrono::duration<double>(now - last_stats_print).count();
117→        auto snapshot = server.snapshot_and_reset_stats();
118→
119→        std::string stats_msg = "=== Stats ===\n  DDS receive rates:";
120→        if (snapshot.topic_receive_counts.empty()) {
121→          stats_msg += "\n    (no subscriptions)";
122→        } else {
123→          for (const auto& [topic, count] : snapshot.topic_receive_counts) {
124→            stats_msg += fmt::format("\n    {}: {:.1f} msg/s", topic, static_cast<double>(count) / elapsed);
125→          }
126→        }
127→
128→        stats_msg +=
129→            fmt::format("\n  Publish frequency: {:.1f} Hz", static_cast<double>(snapshot.publish_cycles) / elapsed);
130→        uint64_t delta_bytes = snapshot.total_bytes_published - prev_bytes_published;
131→        prev_bytes_published = snapshot.total_bytes_published;
132→        stats_msg +=
133→            fmt::format("\n  Sent: {:.2f} MB/s", static_cast<double>(delta_bytes) / elapsed / (1024.0 * 1024.0));
134→
135→        spdlog::info(stats_msg);
136→        last_stats_print = now;
137→      }
138→
139→      std::this_thread::sleep_for(std::chrono::milliseconds(1));
140→    }
141→
142→    spdlog::info("Shutting down...");
143→
144→    // Explicit ordered shutdown to avoid use-after-free:
145→    // 1. Clear DDS message callback
146→    spdlog::debug("[shutdown] Clearing DDS message callback...");
147→    sub_manager->set_message_callback(nullptr);
148→    // 2. Unsubscribe all DDS readers
149→    spdlog::debug("[shutdown] Unsubscribing all DDS readers...");
150→    sub_manager->unsubscribe_all();
151→    // 3. Shutdown WebSocket server
152→    spdlog::debug("[shutdown] Shutting down WebSocket middleware...");
153→    middleware->shutdown();
154→    spdlog::debug("[shutdown] Cleanup complete, exiting scope (destructors will run)...");
155→  } catch (const std::exception& e) {
156→    spdlog::error("Fatal error: {}", e.what());
157→    return 1;
158→  }
159→
160→  return 0;
161→}
