178→void DdsSubscriptionManager::unsubscribe_all() {
179→  std::unordered_map<std::string, SubscriptionInfo> to_close;
180→
181→  {
182→    std::lock_guard<std::mutex> lock(mutex_);
183→    to_close.swap(subscriptions_);
184→  }
185→
186→  spdlog::debug("[shutdown] unsubscribe_all: {} subscriptions to close", to_close.size());
187→  for (auto& [name, info] : to_close) {
188→    spdlog::debug("[shutdown] Closing reader for '{}'...", name);
189→    close_reader(name, info);
190→    spdlog::debug("[shutdown] Closed '{}'", name);
191→  }
192→  spdlog::debug("[shutdown] unsubscribe_all complete");
